let select_all=document.querySelector("#select-all");select_all?.addEventListener("click",(function(btn){select_all.classList.toggle("selected");if(select_all.classList.contains("selected")){select_all.innerText="Снять выбор";select_all.classList.remove("btn-outline-primary");select_all.classList.add("btn-primary")}else{select_all.innerText="Выбрать все";select_all.classList.add("btn-outline-primary");select_all.classList.remove("btn-primary")}const items=document.querySelectorAll('input[data-formname="'+this.dataset.name+'"]');items.forEach((checkbox=>{if(!checkbox.disabled){checkbox.checked=select_all.classList.contains("selected")}}));const btn_sale=document.querySelector("#btn_sale_"+this.dataset.name);const checkboxes=document.querySelectorAll('input[data-formname="'+this.dataset.name+'"]');const atLeastOneChecked=Array.from(checkboxes).some((cb=>cb.checked));if(atLeastOneChecked){btn_sale.classList.remove("d-none")}else{btn_sale.classList.add("d-none")}}));var checkboxs_all=document.querySelectorAll('input[data-formname="'+select_all.dataset.name+'"]');for(checkbox of checkboxs_all){checkbox?.addEventListener("click",(function(){const checkboxes=document.querySelectorAll('input[data-formname="'+select_all.dataset.name+'"]');const atLeastOneChecked=Array.from(checkboxes).some((cb=>cb.checked));const btn_sale=document.querySelector("#btn_sale_"+select_all.dataset.name);if(atLeastOneChecked){btn_sale.classList.remove("d-none")}else{btn_sale.classList.add("d-none")}}))}